-- 008_seed_baseline_voice_profile.sql
-- Seeds the default baseline voice profile with modern human corpus data.
-- 29 elements parsed from 316 diverse sources (Wikipedia, news, tech blogs, dev.to).
-- ~432K words total. Generated by Phase 4.5.3 (Session 20).

BEGIN;

-- 1. Ensure baseline profile exists
VALUES (1, 'Baseline', 'Generic modern human voice profile from 316 diverse sources (Wikipedia, news, tech blogs, dev.to). 431,939 total words. 29 elements.', 'baseline', true)
ON CONFLICT (id) DO UPDATE SET
  description = EXCLUDED.description;

-- 2. Clear existing elements for baseline
DELETE FROM profile_elements WHERE voice_profile_id = 1;

-- 3. Insert 29 parsed elements

-- 4. Set active baseline in settings
UPDATE settings SET active_baseline_id = 1 WHERE id = 1 AND EXISTS (SELECT 1 FROM voice_profiles WHERE id = 1);

COMMIT;